import React, { useState, useContext } from "react";
import "./LoginPopup.css";
import { assets } from "../../assets/assets";
import { StoreContext } from "../../context/StoreContext";
import axios from "axios";

function LoginPopup({ setShowLogin }) {
  const { url, setToken } = useContext(StoreContext);

  // ✅ Saare useState variables use ho rahe hain
  const [currState, setCurrState] = useState("Login");
  const [data, setData] = useState({
    name: "",
    email: "",
    password: "",
  });

  // ✅ Ye function use ho raha hai (input onChange mein)
  const onChangeHandler = (event) => {
    const name = event.target.name;
    const value = event.target.value;
    setData((data) => ({ ...data, [name]: value }));
  };

  

  const onLogin = async (event) => {
  event.preventDefault();
  
  try {
    console.log("📤 Sending data:", data); // Debug
    
    const response = await axios.post(
      currState === "Login" ? `${url}/api/user/login` : `${url}/api/user/register`,
      data
    );

    console.log("📥 Response:", response.data); // Debug

    if (response.data.success) {
      setToken(response.data.token);
      localStorage.setItem("token", response.data.token);
      alert(response.data.message || `${currState} successful!`);
      setShowLogin(false);
    } else {
      alert(response.data.message || "Something went wrong!");
    }
  } catch (error) {
    console.error("❌ Full error:", error);
    console.error("❌ Error response:", error.response?.data); // 👈 IMPORTANT
    
    if (error.response) {
      // Server ne response diya
      alert(`Error ${error.response.status}: ${error.response.data.message || 'Bad Request'}`);
      console.log("Server response:", error.response.data);
    } else if (error.request) {
      // Request gayi par response nahi aaya
      alert("No response from server. Check if backend is running.");
    } else {
      alert(`Error: ${error.message}`);
    }
  }
};

  return (
    <div className="login-popup">
      <form onSubmit={onLogin} className="login-popup-container">
        <div className="login-popup-title">
          <h2>{currState}</h2>
          <img
            onClick={() => setShowLogin(false)}
            src={assets.cross_icon}
            alt=""
          />
        </div>
        <div className="login-popup-inputs">
          {currState === "Login" ? (
            <></>
          ) : (
            <input
              name="name"
              onChange={onChangeHandler}  // ✅ onChangeHandler use ho raha hai
              value={data.name}
              type="text"
              placeholder="Your name"
              required
            />
          )}

          <input
            name="email"
            onChange={onChangeHandler}    // ✅ onChangeHandler use ho raha hai
            value={data.email}
            type="email"
            placeholder="Your email"
            required
          />
          <input
            name="password"
            onChange={onChangeHandler}    // ✅ onChangeHandler use ho raha hai
            value={data.password}
            minLength={10}
            type="password"
            placeholder="password"
            required
          />
        </div>
        <button type="submit">
          {currState === "Sign Up" ? "Create Account" : "Login"}
        </button>
        <div className="login-popup-condition">
          <input type="checkbox" required />
          <p> By continuing a agree to the terms of use & privacy policy</p>
        </div>
        {currState === "Login" ? (
          <p>
            create a new Account?{" "}
            <span onClick={() => setCurrState("Sign Up")}>Click hare</span>
          </p>
        ) : (
          <p>
            {" "}
            Already have an account?
            <span onClick={() => setCurrState("Login")}>Login here</span>
          </p>
        )}
      </form>
    </div>
  );
}

export default LoginPopup;
